package apikeys

import (
	"testing"

	"github.com/stretchr/testify/assert"
)

func TestApiKeyEntitySmall(t *testing.T) {
	t.Run("GenerateNewApiKey: 正しいフォーマットで plain key が生成される", func(t *testing.T) {
		apiKey := NewPlainApiKey()

		assert.Regexp(t, "^jukubox_[A-Za-z0-9\\-_]{43}$", apiKey.PlainKey)
	})

	t.Run("GenerateNewApiKey: 正しいフォーマットで plain key が生成される", func(t *testing.T) {
		apiKey := NewPlainApiKey()

		assert.Regexp(t, "^jukubox_[A-Za-z0-9\\-_]{43}$", apiKey.PlainKey)
	})

	t.Run("GenerateApiKeyFromPlain: 正しいフォーマットで plain key を設定できる", func(t *testing.T) {
		const plain = "REDACTED"
		apiKey, err := GenerateApiKeyFromPlainKey(plain)

		assert.Equal(t, plain, apiKey.PlainKey)
		assert.NoError(t, err)
	})

	t.Run("GenerateApiKeyFromPlain: 正しくないフォーマットでエラーを返す（prefix なし）", func(t *testing.T) {
		const plain = "REDACTED"
		_, err := GenerateApiKeyFromPlainKey(plain)

		assert.ErrorIs(t, err, ErrApiKeyIsInvalidFormat)
	})

	t.Run("GenerateApiKeyFromPlain: 正しくないフォーマットでエラーを返す（base64 でない文字）", func(t *testing.T) {
		const plain = "REDACTED$"
		_, err := GenerateApiKeyFromPlainKey(plain)

		assert.ErrorIs(t, err, ErrApiKeyIsInvalidFormat)
	})

	t.Run("GetHash: SHA-256 hex 形式で返される", func(t *testing.T) {
		hash := NewPlainApiKey().GetHash()
		assert.Regexp(t, "^[0-9a-f]{64}$", hash)
	})

	t.Run("GetHash: 同じキーから同じハッシュが生成される", func(t *testing.T) {
		apiKey := NewPlainApiKey()
		assert.Equal(t, apiKey.GetHash(), apiKey.GetHash())
	})

	t.Run("GetHash: 異なるキーからは異なるハッシュが生成される", func(t *testing.T) {
		a := NewPlainApiKey()
		b := NewPlainApiKey()
		assert.NotEqual(t, a.GetHash(), b.GetHash())
	})
}

package apikeys

import (
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"encoding/hex"
	"fmt"
	"time"

	"github.com/harusame0616/ijuku/apps/api/lib/uuid"
)

type HashedApiKey struct {
	ApiKeyID          string
	HashedApiKey      string
	PlainApiKeySuffix string
	UserID            string
	ExpiredAt         *time.Time
}

type NewHashedApiKeyArg struct {
	UserID    string
	ExpiredAt *time.Time
}

const ApiKeyMaxCount = 5

func NewHashedApiKey(arg NewHashedApiKeyArg) (hashedApiKey HashedApiKey, plainKey string) {
	b := make([]byte, 32)
	rand.Read(b)

	plainKey = generatePlainApiKey()
	hashedApiKey = HashedApiKey{
		ApiKeyID:          uuid.MustNewUuidString(),
		UserID:            arg.UserID,
		HashedApiKey:      getHash(plainKey),
		PlainApiKeySuffix: plainKey[len(plainKey)-4:],
		ExpiredAt:         arg.ExpiredAt,
	}

	return hashedApiKey, plainKey
}

func getHash(plain string) string {
	hash := sha256.Sum256([]byte(plain))
	return hex.EncodeToString(hash[:])
}

func generatePlainApiKey() string {
	b := make([]byte, 32)
	rand.Read(b)

	return fmt.Sprintf("jukubox_%s", base64.RawURLEncoding.EncodeToString(b))
}

